# ==========================
# HELPERS
# ==========================
def preprocess_image(img_array):
    """Convert to 64x64 grayscale, flatten."""
    gray = cv2.cvtColor(img_array, cv2.COLOR_RGB2GRAY)
    resized = cv2.resize(gray, (64, 64))
    flat = resized.flatten().reshape(1, -1).astype(np.float32)
    return flat, resized

def predict(flat_features):
    scaled = scaler.transform(flat_features)
    pred_idx = model.predict(scaled)[0]
    proba = model.predict_proba(scaled)[0]
    pred_label = encoder.classes_[pred_idx]
    return pred_label.capitalize(), proba, pred_idx

